create table if not exists organizations(id uuid primary key default gen_random_uuid(),name text not null,created_at timestamptz default now());
create table if not exists org_memberships(id uuid primary key default gen_random_uuid(),org_id uuid references organizations(id),user_id uuid not null,role text not null,supplier_id uuid);
create table if not exists projects(id uuid primary key default gen_random_uuid(),org_id uuid references organizations(id),name text,code text,location text,status text,start_date date,end_date date);
create table if not exists suppliers(id uuid primary key default gen_random_uuid(),org_id uuid references organizations(id),name text,contact_email text,phone text,address text,status text);
create table if not exists plants(id uuid primary key default gen_random_uuid(),org_id uuid references organizations(id),supplier_id uuid references suppliers(id),name text,plant_code text,category text,unit_type text,status text);
create table if not exists plant_rates(id uuid primary key default gen_random_uuid(),org_id uuid references organizations(id),plant_id uuid references plants(id),supplier_id uuid references suppliers(id),project_id uuid references projects(id),rate_type text,hourly_rate numeric,daily_rate numeric,overtime_rate numeric,currency text,effective_from date,effective_to date);
create table if not exists ipc_periods(id uuid primary key default gen_random_uuid(),org_id uuid references organizations(id),project_id uuid,supplier_id uuid,start_date date,end_date date,status text default 'finalized',subtotal numeric default 0,created_at timestamptz default now());
create table if not exists plant_logs(id uuid primary key default gen_random_uuid(),org_id uuid references organizations(id),project_id uuid references projects(id),plant_id uuid references plants(id),supplier_id uuid references suppliers(id),ipc_period_id uuid references ipc_periods(id),date date,hours_worked numeric,idle_hours numeric,breakdown_hours numeric,description text,logged_by uuid,status text default 'draft');
create table if not exists ipc_lines(id uuid primary key default gen_random_uuid(),ipc_period_id uuid references ipc_periods(id),plant_log_id uuid references plant_logs(id),rate numeric,amount numeric,warning text);
create table if not exists approval_events(id uuid primary key default gen_random_uuid(),log_id uuid references plant_logs(id),actor_id uuid,action text,comment text,created_at timestamptz default now());
create table if not exists import_batches(id uuid primary key default gen_random_uuid(),org_id uuid references organizations(id),uploaded_by uuid,filename text,status text,created_at timestamptz default now());
create table if not exists import_rows(id uuid primary key default gen_random_uuid(),batch_id uuid references import_batches(id),payload jsonb,valid boolean,errors text[]);
create index if not exists idx_logs_org on plant_logs(org_id); create index if not exists idx_logs_keys on plant_logs(project_id,supplier_id,plant_id,date,status);
alter table organizations enable row level security;
create policy org_read on organizations for select using (exists(select 1 from org_memberships m where m.org_id=id and m.user_id=auth.uid()));
